import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"死神之眼","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/3.瞳术/死神之眼.md","filePath":"4.资源分区/3.瞳术/死神之眼.md"}'),d={name:"4.资源分区/3.瞳术/死神之眼.md"};function l(_,a,i,b,p,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"死神之眼",tabindex:"-1"},[s("死神之眼 "),e("a",{class:"header-anchor",href:"#死神之眼","aria-label":'Permalink to "死神之眼"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌033")])])],-1),o('<h1 id="死神之眼-1" tabindex="-1">死神之眼 <a class="header-anchor" href="#死神之眼-1" aria-label="Permalink to &quot;死神之眼&quot;">​</a></h1><p>死神之眼（一次性瞳术）<br> C+1200<br> 死神与人类有着重要的不同，其中之一便是，死神的眼睛。<br> 签下契约，支付一半的寿命，即使不是死神，也能得到死神之眼。<br> 虽然你支付了一半的寿命，但并不会影响你对衰老的抵抗，因为死亡笔记中寿命的定义是指你本应死去的时间，所以支付一半寿命只是会让你本该死亡的时间提前到来，至于你在何时会死亡，只有那就只有死神和ST才知道了，顺便一提，即使你退掉死神之眼，这个寿命也不会返还。<br> 由于你支付了相应的支线与分数，主神非常“良心”地提供了增值服务，你的死神之眼并不依附死亡笔记存在，即使你不拥有死亡笔记，死神之眼也不会消失。但寿命该扣还是扣掉了。<br> 死神的眼睛只要盯着一个人的脸（或相片，影像之类）看，就可以看见那个人的名字和寿命。<br> 死神之眼无法从画像看到一个人的名字和寿命，不管那幅画多逼真。但从电视或相片是可以看到的。<br> 死神之眼无法看到自己和其他笔记本持有者的寿命，只能看到名字，已死的人则无法看到名字与寿命。<br> 死神之眼所看到的名字和户籍中有无登记并没有关系，而是可以用笔记本杀掉那个人时所用的名字。（有可能是指那个人自己认知中的本名）<br> 取得死神之眼的人类都会拥有3.6以上的视力。<br> 顺便一提，虽然死神之眼能看到寿命，但实际上这个寿命是用一串数字表示，并且使用的并非是人类的历法，虽然你可以看到用来表示寿命的数字，但你根本看不懂这到底意味着对方会在什么时候死去。<br> 若一个单位免疫A级别解析/预知效果，则你将无法看清它的真名</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',4)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
